const ALLOWED_ORIGINS = ['https://example.com', 'https://app.example.com'];
const RATE_LIMIT_REQUESTS = 100;
const RATE_LIMIT_WINDOW = 60000;

async function hashIP(ip) {
  const encoder = new TextEncoder();
  const data = encoder.encode(ip);
  const hashBuffer = await crypto.subtle.digest('SHA-256', data);
  const hashArray = Array.from(new Uint8Array(hashBuffer));
  return hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
}

async function checkRateLimit(request, env) {
  const ip = request.headers.get('CF-Connecting-IP') || 'unknown';
  const hashedIP = await hashIP(ip);
  const key = `ratelimit:${hashedIP}`;
  
  const current = await env.RATE_LIMITER?.get(key);
  const count = current ? parseInt(current) : 0;
  
  if (count >= RATE_LIMIT_REQUESTS) {
    return false;
  }
  
  await env.RATE_LIMITER?.put(key, (count + 1).toString(), {
    expirationTtl: RATE_LIMIT_WINDOW / 1000
  });
  
  return true;
}

function validateOrigin(request) {
  const origin = request.headers.get('Origin');
  if (!origin) return true;
  return ALLOWED_ORIGINS.includes(origin);
}

function sanitizeInput(data) {
  if (typeof data === 'string') {
    return data.replace(/[<>\"'&]/g, '');
  }
  if (typeof data === 'object' && data !== null) {
    const sanitized = {};
    for (const [key, value] of Object.entries(data)) {
      sanitized[key] = sanitizeInput(value);
    }
    return sanitized;
  }
  return data;
}

async function validateRequest(request) {
  const contentType = request.headers.get('Content-Type');
  
  if (request.method === 'POST' || request.method === 'PUT') {
    if (!contentType || !contentType.includes('application/json')) {
      return { valid: false, error: 'Invalid Content-Type' };
    }
  }
  
  const url = new URL(request.url);
  if (url.pathname.includes('..') || url.pathname.includes('//')) {
    return { valid: false, error: 'Invalid path' };
  }
  
  return { valid: true };
}

async function handleRequest(request, env) {
  if (!validateOrigin(request)) {
    return new Response('Forbidden', { status: 403 });
  }
  
  if (env.RATE_LIMITER && !(await checkRateLimit(request, env))) {
    return new Response('Rate limit exceeded', { status: 429 });
  }
  
  const validation = await validateRequest(request);
  if (!validation.valid) {
    return new Response(validation.error, { status: 400 });
  }
  
  const url = new URL(request.url);
  const path = url.pathname;
  
  try {
    if (path.startsWith('/api/auth/')) {
      return await routeToAuth(request, env);
    } else if (path.startsWith('/api/data/')) {
      return await routeToData(request, env);
    } else if (path.startsWith('/api/analytics/')) {
      return await routeToAnalytics(request, env);
    } else {
      return new Response('Not Found', { status: 404 });
    }
  } catch (error) {
    console.error('Error handling request:', error);
    return new Response('Internal Server Error', { status: 500 });
  }
}

async function routeToAuth(request, env) {
  const clonedRequest = new Request(request.url, {
    method: request.method,
    headers: request.headers,
    body: request.body
  });
  
  const response = await env.AUTH_SERVICE.fetch(clonedRequest);
  return response;
}

async function routeToData(request, env) {
  const authHeader = request.headers.get('Authorization');
  if (!authHeader) {
    return new Response('Unauthorized', { status: 401 });
  }
  
  const authRequest = new Request('https://internal/verify', {
    method: 'POST',
    headers: { 'Authorization': authHeader }
  });
  
  const authResponse = await env.AUTH_SERVICE.fetch(authRequest);
  if (!authResponse.ok) {
    return new Response('Unauthorized', { status: 401 });
  }
  
  const clonedRequest = new Request(request.url, {
    method: request.method,
    headers: request.headers,
    body: request.body
  });
  
  return await env.DATA_SERVICE.fetch(clonedRequest);
}

async function routeToAnalytics(request, env) {
  const clonedRequest = new Request(request.url, {
    method: request.method,
    headers: request.headers,
    body: request.body
  });
  
  return await env.ANALYTICS_SERVICE.fetch(clonedRequest);
}

export default {
  async fetch(request, env, ctx) {
    const response = await handleRequest(request, env);
    
    const corsHeaders = {
      'Access-Control-Allow-Origin': ALLOWED_ORIGINS[0],
      'Access-Control-Allow-Methods': 'GET, POST, PUT, DELETE, OPTIONS',
      'Access-Control-Allow-Headers': 'Content-Type, Authorization',
      'X-Content-Type-Options': 'nosniff',
      'X-Frame-Options': 'DENY',
      'X-XSS-Protection': '1; mode=block',
      'Strict-Transport-Security': 'max-age=31536000; includeSubDomains'
    };
    
    if (request.method === 'OPTIONS') {
      return new Response(null, { headers: corsHeaders });
    }
    
    const newResponse = new Response(response.body, response);
    Object.entries(corsHeaders).forEach(([key, value]) => {
      newResponse.headers.set(key, value);
    });
    
    return newResponse;
  }
};

// src/auth-worker.js
const SECRET_KEY = 'your-secret-key-change-in-production';
const TOKEN_EXPIRY = 3600;

async function generateToken(userId) {
  const header = { alg: 'HS256', typ: 'JWT' };
  const payload = {
    userId: userId,
    exp: Math.floor(Date.now() / 1000) + TOKEN_EXPIRY,
    iat: Math.floor(Date.now() / 1000)
  };
  
  const encodedHeader = btoa(JSON.stringify(header));
  const encodedPayload = btoa(JSON.stringify(payload));
  const signature = await sign(`${encodedHeader}.${encodedPayload}`, SECRET_KEY);
  
  return `${encodedHeader}.${encodedPayload}.${signature}`;
}

async function sign(data, secret) {
  const encoder = new TextEncoder();
  const key = await crypto.subtle.importKey(
    'raw',
    encoder.encode(secret),
    { name: 'HMAC', hash: 'SHA-256' },
    false,
    ['sign']
  );
  
  const signature = await crypto.subtle.sign(
    'HMAC',
    key,
    encoder.encode(data)
  );
  
  return btoa(String.fromCharCode(...new Uint8Array(signature)));
}

async function verifyToken(token) {
  try {
    const parts = token.split('.');
    if (parts.length !== 3) return null;
    
    const [encodedHeader, encodedPayload, signature] = parts;
    const expectedSignature = await sign(`${encodedHeader}.${encodedPayload}`, SECRET_KEY);
    
    if (signature !== expectedSignature) return null;
    
    const payload = JSON.parse(atob(encodedPayload));
    
    if (payload.exp < Math.floor(Date.now() / 1000)) return null;
    
    return payload;
  } catch (error) {
    return null;
  }
}

async function handleAuthRequest(request, env) {
  const url = new URL(request.url);
  const path = url.pathname;
  
  if (path === '/api/auth/login' && request.method === 'POST') {
    const body = await request.json();
    const { username, password } = body;
    
    if (!username || !password) {
      return new Response(JSON.stringify({ error: 'Missing credentials' }), {
        status: 400,
        headers: { 'Content-Type': 'application/json' }
      });
    }
    
    const userRequest = new Request('https://internal/user/validate', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ username, password })
    });
    
    const userResponse = await env.DATA_SERVICE.fetch(userRequest);
    
    if (!userResponse.ok) {
      return new Response(JSON.stringify({ error: 'Invalid credentials' }), {
        status: 401,
        headers: { 'Content-Type': 'application/json' }
      });
    }
    
    const userData = await userResponse.json();
    const token = await generateToken(userData.userId);
    
    return new Response(JSON.stringify({ token, userId: userData.userId }), {
      status: 200,
      headers: { 'Content-Type': 'application/json' }
    });
  }
  
  if (path === '/verify' && request.method === 'POST') {
    const authHeader = request.headers.get('Authorization');
    if (!authHeader || !authHeader.startsWith('Bearer ')) {
      return new Response('Unauthorized', { status: 401 });
    }
    
    const token = authHeader.substring(7);
    const payload = await verifyToken(token);
    
    if (!payload) {
      return new Response('Invalid token', { status: 401 });
    }
    
    return new Response(JSON.stringify({ userId: payload.userId }), {
      status: 200,
      headers: { 'Content-Type': 'application/json' }
    });
  }
  
  return new Response('Not Found', { status: 404 });
}

export default {
  async fetch(request, env, ctx) {
    return await handleAuthRequest(request, env);
  }
};

