const MOCK_USERS = {
  'admin': { userId: '1', username: 'admin', passwordHash: 'hashed_password' },
  'user1': { userId: '2', username: 'user1', passwordHash: 'hashed_password' }
};

const MOCK_DATA = {
  '1': { name: 'Admin User', email: 'admin@example.com', role: 'admin' },
  '2': { name: 'Regular User', email: 'user@example.com', role: 'user' }
};

async function handleDataRequest(request, env) {
  const url = new URL(request.url);
  const path = url.pathname;
  
  if (path === '/user/validate' && request.method === 'POST') {
    const body = await request.json();
    const { username, password } = body;
    
    const user = MOCK_USERS[username];
    if (!user) {
      return new Response('User not found', { status: 404 });
    }
    
    return new Response(JSON.stringify({ userId: user.userId }), {
      status: 200,
      headers: { 'Content-Type': 'application/json' }
    });
  }
  
  if (path.startsWith('/api/data/user/') && request.method === 'GET') {
    const userId = path.split('/').pop();
    const userData = MOCK_DATA[userId];
    
    if (!userData) {
      return new Response('User not found', { status: 404 });
    }
    
    const analyticsRequest = new Request('https://internal/track', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        event: 'user_data_accessed',
        userId: userId,
        timestamp: Date.now()
      })
    });
    
    env.ANALYTICS_SERVICE.fetch(analyticsRequest).catch(err => {
      console.error('Analytics error:', err);
    });
    
    return new Response(JSON.stringify(userData), {
      status: 200,
      headers: { 'Content-Type': 'application/json' }
    });
  }
  
  if (path === '/api/data/users' && request.method === 'GET') {
    const users = Object.values(MOCK_DATA);
    
    return new Response(JSON.stringify(users), {
      status: 200,
      headers: { 'Content-Type': 'application/json' }
    });
  }
  
  return new Response('Not Found', { status: 404 });
}

export default {
  async fetch(request, env, ctx) {
    return await handleDataRequest(request, env);
  }
};

// src/analytics-worker.js
const events = [];

async function handleAnalyticsRequest(request, env) {
  const url = new URL(request.url);
  const path = url.pathname;
  
  if (path === '/track' && request.method === 'POST') {
    const body = await request.json();
    
    const event = {
      ...body,
      id: crypto.randomUUID(),
      receivedAt: Date.now()
    };
    
    events.push(event);
    
    if (events.length > 1000) {
      events.shift();
    }
    
    return new Response(JSON.stringify({ success: true, eventId: event.id }), {
      status: 200,
      headers: { 'Content-Type': 'application/json' }
    });
  }
  
  if (path === '/api/analytics/events' && request.method === 'GET') {
    const limit = parseInt(url.searchParams.get('limit') || '100');
    const recentEvents = events.slice(-limit);
    
    return new Response(JSON.stringify(recentEvents), {
      status: 200,
      headers: { 'Content-Type': 'application/json' }
    });
  }
  
  if (path === '/api/analytics/stats' && request.method === 'GET') {
    const stats = {
      totalEvents: events.length,
      eventTypes: events.reduce((acc, event) => {
        acc[event.event] = (acc[event.event] || 0) + 1;
        return acc;
      }, {})
    };
    
    return new Response(JSON.stringify(stats), {
      status: 200,
      headers: { 'Content-Type': 'application/json' }
    });
  }
  
  return new Response('Not Found', { status: 404 });
}

export default {
  async fetch(request, env, ctx) {
    return await handleAnalyticsRequest(request, env);
  }
};